```plantuml
@startuml
skinparam classAttributeIconSize 0
skinparam packageStyle folder

package java {
  package time {
    class LocalDate
  }
  package util {
    interface List<T>
    class URL
  }
}

package org {
  package springframework {
    package hateoas {
      class RepresentationModel<T>
    }
  }
}

package com {
  package acme {
    package filiale {
      package rest {
        class KundeModel <<entity>> {
          name : String
          email : String
          kategorie: Int
          hasNewsletter: Boolean
          geburtsdatum: LocalDate
          homepage: URL
          geschlecht: GeschlechtType
          familienstand: FamilienstandType
          interessen: List<InteresseType>
        }
      }
      package entity {
        class Kunde
        class Umsatz
        class Adresse
        enum GeschlechtType
        enum FamilienstandType
        enum InteresseType
      }
    }
  }
}

KundeModel .up.> LocalDate
KundeModel .up.> List
KundeModel .up.> URL
KundeModel -up-|> RepresentationModel

KundeModel .down.> Kunde
KundeModel *-- Umsatz : umsatz > \n 0..1
KundeModel *-- Adresse : adresse > \n 1
KundeModel .down.> GeschlechtType
KundeModel .down.> FamilienstandType
KundeModel .down.> InteresseType

center footer (c) Jürgen Zimmermann
@enduml
```
